// Extrai configurações do payload ou usa defaults
const body = $input.first().json.body ?? $input.first().json;

const cidades = body.cidades ?? ['Cotia', 'Vargem Grande Paulista', 'Itapevi', 'Embu das Artes', 'Osasco'];
const raio_km = body.raio_km ?? 30;
const limite_diario = body.limite_diario ?? 30;

// Horário comercial: seg-sex, 9h-17h30, sem 12h-13h30
const agora = new Date();
const hora = agora.getHours();
const minuto = agora.getMinutes();
const diaSemana = agora.getDay(); // 0=Dom, 6=Sáb

const fimDeSemana = diaSemana === 0 || diaSemana === 6;
const foraDo_horario = hora < 9 || (hora === 17 && minuto > 30) || hora >= 18;
const almoco = hora === 12 || (hora === 13 && minuto < 30);

if (fimDeSemana || foraDo_horario || almoco) {
  return [{ json: { skip: true, motivo: 'Fora do horário comercial', cidades, raio_km, limite_diario } }];
}

return [{ json: { skip: false, cidades, raio_km, limite_diario } }];

// Verifica quantas mensagens já foram enviadas hoje via Supabase REST
const SUPABASE_URL = $env['SUPABASE_URL'];
const SUPABASE_SERVICE_KEY = $env['SUPABASE_SERVICE_KEY'];
const limite_diario = $json.limite_diario;

const hoje = new Date().toISOString().slice(0, 10);
const url = `${SUPABASE_URL}/rest/v1/leads?select=count&enviado_em=gte.${hoje}T00:00:00&status=neq.capturado`;

const res = await fetch(url, {
  headers: {
    apikey: SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
    Prefer: 'count=exact',
    Range: '0-0',
  },
});

const countHeader = res.headers.get('content-range');
const total = parseInt(countHeader?.split('/')[1] ?? '0', 10);
const restante = Math.max(0, limite_diario - total);

return [{ json: { ...$json, enviados_hoje: total, restante, limite_diario } }];

// Pega uma cidade aleatória das cidades configuradas
const cidades = $json.cidades;
const cidade = cidades[Math.floor(Math.random() * cidades.length)];
return [{ json: { ...$json, cidade_atual: cidade } }];

// Filtra empresas sem telefone ou já processadas
const item = $json;
const placeId = item.place_id;
if (!placeId) return [];

// Busca detalhes para pegar telefone
const GOOGLE_KEY = $env['GOOGLE_PLACES_API_KEY'];
const detailUrl = `https://maps.googleapis.com/maps/api/place/details/json?place_id=${placeId}&fields=name,formatted_phone_number,website,rating,user_ratings_total,formatted_address,types&key=${GOOGLE_KEY}&language=pt-BR`;

const res = await fetch(detailUrl);
const data = await res.json();
const result = data.result;

if (!result) return [];

const telefone = result.formatted_phone_number;
if (!telefone) return []; // Sem telefone = descarta

// Extrai segmento dos types do Google
const typeMap: Record<string, string> = {
  restaurant: 'Restaurante',
  food: 'Alimentação',
  health: 'Saúde',
  beauty_salon: 'Beleza',
  hair_care: 'Beleza',
  store: 'Varejo',
  clothing_store: 'Moda',
  electronics_store: 'Eletrônicos',
  furniture_store: 'Móveis',
  gym: 'Academia',
  real_estate_agency: 'Imobiliária',
  car_repair: 'Automotivo',
  car_dealer: 'Automotivo',
  lawyer: 'Advocacia',
  accounting: 'Contabilidade',
  dentist: 'Odontologia',
  doctor: 'Medicina',
  school: 'Educação',
  lodging: 'Hospedagem',
};

const types = result.types ?? [];
let segmento = 'Outros';
for (const t of types) {
  if (typeMap[t]) { segmento = typeMap[t]; break; }
}

return [{
  json: {
    empresa: result.name,
    telefone: telefone.replace(/[^\d+]/g, ''),
    cidade: $('Escolhe Cidade').first().json.cidade_atual,
    endereco: result.formatted_address,
    segmento,
    website: result.website ?? null,
    google_place_id: placeId,
    rating: result.rating ?? null,
    total_reviews: result.user_ratings_total ?? null,
    raio_km: $('Escolhe Cidade').first().json.raio_km,
  }
}];

// Verifica se o lead é novo (não duplicata)
const SUPABASE_URL = $env['SUPABASE_URL'];
const SUPABASE_SERVICE_KEY = $env['SUPABASE_SERVICE_KEY'];
const google_place_id = $json.google_place_id;

const res = await fetch(
  `${SUPABASE_URL}/rest/v1/leads?google_place_id=eq.${encodeURIComponent(google_place_id)}&select=id,status`,
  {
    headers: {
      apikey: SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
    },
  }
);

const data = await res.json();
const lead = data[0];

if (!lead) return []; // Lead não salvo, skip
if (lead.status !== 'capturado') return []; // Já foi processado

return [{ json: { ...$json, lead_id: lead.id } }];

